    if(sync && !sync.dataset.bnsV108){
      sync.dataset.bnsV108='1';
      sync.addEventListener('click',()=>{
        removeGithubEverywhere();
        setTimeout(()=>{
          removeGithubEverywhere();
          updateAlertButton();
          scrubDOM();
        },50);
      },true);
    }
