  function addMatV45(mid){
    var s = appState();
    var m = (s.materials || []).find(function(x){
      return String(x.id) === String(mid);
    });
    if (!m) return false;
    var st = fixedMaterialStatus(m);
    if (st.blocked) {
      openMaterialPopup(mid);
      return false;
    }
    var list = chosenList();
    var exists = list.some(function(x){
      return sameMaterial(x,m);
    });
    if (!exists) {
      var c = clone(m);
      c.status = "reserved";
      if (c.qty == null) c.qty = 1;
      if (c.linePrice == null) c.linePrice = 0;
      if (c.lineDeposit == null) c.lineDeposit = 0;
      list.push(c);
      setChosenList(list);
    }
    try {
      if (typeof renderChosen === "function") renderChosen();
    } catch(e) {
    }
    try {
      if (typeof summaryRender === "function") summaryRender();
    } catch(e) {
    }
    try {
      if (typeof calcTotals === "function") calcTotals();
    } catch(e) {
    }
    renderMaterialsV45(window.currentCat || (m.cat || "TW"));
    return false;
  }
