  function cleanOld(){
    A('#bnsV54AdminBox,#bnsV53AdminForm,#bnsV50AdminForm,#bnsV49AdminForm,#bnsV54AdminCard').forEach(function(x){
      try{
        x.remove();
      } catch(e){
      }
    });
    A('#materialCats button,#materialPanel button,#materialCats .worktab,#materialPanel .worktab').forEach(function(b){
      if(N(b.textContent)==='copy opdracht'){
        b.classList.add('bns-hide-copy');
        b.style.display='none';
      }
    });
    var dels=A('button').filter(function(b){
      return N(b.textContent)==='verwijder opdracht';
    });
    dels.forEach(function(b,i){
      if(i>0){
        b.style.display='none';
      }
    });
  }
  function renderCats(){
    var box=E('materialCats');
    if(!box) return;
    var cats={
    };
    (S().materials||[]).forEach(function(m){
      cats[cat(m.cat||m.rubriek||m.category)]=true;
    });
    /* v839: geen vaste demo-rubrieken meer. Alleen echte materiaalrubrieken tonen. */
    var cur=currentCat();
    var catKeys=Object.keys(cats);
    if(!catKeys.length){ box.innerHTML=''; return; }
    box.innerHTML=catKeys.sort(function(a,b){
      var order=['TW','TO','KW','EXTRA'];
      var ia=order.indexOf(a), ib=order.indexOf(b);
      if(ia>=0||ib>=0) return (ia<0?99:ia)-(ib<0?99:ib);
      return a.localeCompare(b);
    }).map(function(c){
      return '<button type="button" class="worktab '+(c===cur?'active':'')+'" data-v56-cat="'+H(c)+'" style="--cat-color:'+color(c)+'">'+H(c)+'</button>';
    }).join('');
    A('[data-v56-cat]',box).forEach(function(b){
      b.onclick=function(ev){
        if(ev){
          ev.preventDefault();
          ev.stopPropagation();
        }
        setCurrentCat(b.getAttribute('data-v56-cat'));
        var s=E('materialSearch');
        if(s) s.value='';
        keep(function(){
          renderCats();
          renderMaterials();
        });
        return false;
      };
    });
  }
  function renderMaterials(){
    if(window.BNS_V392 && typeof window.BNS_V392.renderMaterials==='function') return window.BNS_V392.renderMaterials.apply(this,arguments);

    var box=E('materialList');
    if(!box) return;
    var c=currentCat();
    var q=N((E('materialSearch')||{
    }).value);
    if(!c){ box.innerHTML='<div style="padding:28px;text-align:center;font-weight:900;color:#64748b">Nog geen materiaal aangemaakt.</div>'; return; }
    var mats=(S().materials||[]).filter(function(m){
      return cat(m.cat||m.rubriek||m.category)===c;
    });
    if(q) mats=mats.filter(function(m){
      return searchText(m).indexOf(q)>=0;
    });
    mats=mats.slice(0,250);
    box.innerHTML=mats.length ? mats.map(function(m){
      var st=statusOf(m), cc=cat(m.cat||m.rubriek||m.category), p=product(m), d=desc(m), pr=price(m);
      var main='<div class="bns-v56-title"><b>'+H(codeLine(m))+'</b>'+H(p?(' '+p):'')+'</div>'+(d?'<div class="bns-v56-desc">'+H(d)+'</div>':'')+(pr?'<div class="bns-v56-price">'+H(pr)+'</div>':'');
      return '<div class="bns-v56-row" data-material-id="'+H(m.id)+'" style="--cat-color:'+color(cc)+'"><div class="bns-v56-bar"></div><div>'+main+'</div><span class="bns-v56-pill bns-v56-'+st.key+'">'+H(st.label)+'</span></div>';
    }).join('') : '<div style="padding:28px;text-align:center;font-weight:900;color:#64748b">Geen materiaal gevonden in rubriek '+H(c)+'.</div>';
  }
  function bindMaterial(){
    var search=E('materialSearch');
    if(search && !search.dataset.bnsV56){
      search.dataset.bnsV56='1';
      search.autocomplete='off';
      search.addEventListener('input',function(ev){
        if(ev)ev.stopPropagation();
        keep(renderMaterials);
      },true);
      search.addEventListener('focus',function(){
        keep(function(){
        });
      },true);
    }
    var box=E('materialList');
    if(box && !box.dataset.bnsV56){
      box.dataset.bnsV56='1';
      box.addEventListener('click',function(ev){
        var r=ev.target.closest&&ev.target.closest('[data-material-id]');
        if(!r||!box.contains(r)) return;
        ev.preventDefault();
        ev.stopPropagation();
        if(ev.stopImmediatePropagation) ev.stopImmediatePropagation();
        try{
          window.addMat(r.getAttribute('data-material-id'));
        } catch(e){
        }
        setTimeout(renderMaterials,80);
        return false;
      },true);
    }
  }
