  function driverIdsFromOrder(o){
    var ids=[];
    if(!o) return ids;
    if(Array.isArray(o.driverIds)) ids=ids.concat(o.driverIds.map(String));
    if(Array.isArray(o.bezorgerIds)) ids=ids.concat(o.bezorgerIds.map(String));
    if(Array.isArray(o.drivers)) o.drivers.forEach(function(d){
      if(d&&d.id) ids.push(String(d.id));
    });
    var names=[];
    if(Array.isArray(o.driverNames)) names=names.concat(o.driverNames);
    if(Array.isArray(o.bezorgerNames)) names=names.concat(o.bezorgerNames);
    var s=T(o.driverName||o.driver||o.bezorger);
    if(s) names=names.concat(s.split(/[,;]/).map(T));
    if(names.length){
      users().forEach(function(u){
        if(names.map(L).indexOf(L(u.name))>=0) ids.push(String(u.id));
      });
    }
    return Array.from(new Set(ids.filter(Boolean)));
  }
  function ensureDriverChooser(){
    var sel=E('orderDriver');
    if(!sel) return;
    var box=E('bnsV83DriverBox');
    if(!box){
      box=document.createElement('div');
      box.id='bnsV83DriverBox';
      sel.insertAdjacentElement('afterend',box);
    }
    var selected=[];
    try{
      var nr=val('orderNumber');
      var existing = nr ? findOrderByNumber(nr) : null;
      var isEditing=false;
      try{ isEditing=!!editing; }catch(e){ isEditing=!!window.editing; }

      /*
        BNS v459:
        - Nieuwe opdracht = altijd leeg.
        - Als planner vinkjes aan/uit zet, blijven die staan tot opslaan.
        - Bestaande opdracht leest alleen uit opdracht zolang planner nog niets heeft aangeraakt.
      */
      if(window.__bns459DriverTouched || window.__bns458DriverTouched){
        selected=selectedDriverIds().map(String);
      }else if(isEditing && existing){
        selected=driverIdsFromOrder(existing).map(String);
      }else{
        selected=[];
      }
    }catch(e){ selected=[]; }
    var ds=driverUsers();
    box.innerHTML='<h4>Bezorgers voor deze opdracht</h4><div class="grid">'+(ds.length?ds.map(function(u){
      return '<label><input type="checkbox" value="'+H(u.id)+'" '+(selected.indexOf(String(u.id))>=0?'checked':'')+'> <span>'+H(u.name||'')+'</span></label>';
    }).join(''):'<small>Geen bezorgers aangemaakt.</small>')+'</div>';
    sel.innerHTML='<option value="">Geen</option>'+ds.map(function(u){
      return '<option value="'+H(u.id)+'">'+H(u.name||'')+'</option>';
    }).join('');
    sel.value=selected[0]||'';
    A('input',box).forEach(function(i){
      i.onchange=function(){
        window.__bns458DriverTouched=true; window.__bns459DriverTouched=true;
        var ids=selectedDriverIds();
        sel.value=ids[0]||'';
      };
    });
  }
