  function patchOrderSave(){
    var btn=E('saveOrder');
    if(btn && btn.dataset.bnsV83Save!=='1'){
      var oldClick=btn.onclick;
      var fresh=btn.cloneNode(true);
      fresh.dataset.bnsV83Save='1';
      fresh.onclick=function(ev){
        if(ev){
          ev.preventDefault();
          ev.stopPropagation();
          if(ev.stopImmediatePropagation) ev.stopImmediatePropagation();
        }
        var nr=val('orderNumber');
        var touched=!!(window.__bns458DriverTouched || window.__bns459DriverTouched || window.__bns474DriverTouched || window.__bns516DriverTouched);
        var before=cloneDriverFields(findOrderByNumber(nr));
        var r=false;
        try{
          if(typeof window.saveCurrentOrder==='function') r=window.saveCurrentOrder();
          else if(typeof saveCurrentOrder==='function') r=saveCurrentOrder();
          else if(typeof oldClick==='function') r=oldClick.call(this,ev);
        } catch(e){
          console.error(e);
        }
        setTimeout(function(){
          var o=findOrderByNumber(nr);
          if(o){
            if(touched){
              applyDriversToOrder(o);
            }else{
              restoreDriversIfMissing(o,before);
            }
            saveLocal();
            syncDoc('orders',o.id,o);
            renderPhone83();
            try{
              if(typeof renderOrders==='function') renderOrders();
            } catch(e){
            }
            window.__bns458DriverTouched=false; window.__bns459DriverTouched=false; window.__bns474DriverTouched=false; window.__bns516DriverTouched=false;
          }
        },160);
        return false;
      };
      btn.parentNode.replaceChild(fresh,btn);
    }
    var old=window.editOrder || (typeof editOrder==='function'?editOrder:null);
    if(old && !old.__bnsV83){
      var nw=function(id){
        var r=old.apply(this,arguments);
        setTimeout(function(){
          var o=orders().find(function(x){
            return String(x.id)===String(id);
          });
          setSelectedDrivers(driverIdsFromOrder(o));
        },180);
        return r;
      };
      nw.__bnsV83=true;
      window.editOrder=nw;
      try{
        editOrder=nw;
      } catch(e){
      }
    }
  }
