      for(var i=0;i<vals.length;i++){ var c=canonCode(vals[i]); if(c) return c; }
      // Alleen als naam/omschrijving zelf een echte code bevat, niet op naamtekst matchen.
      vals=[m.name,m.description,m.beschrijving];
