    m.id='tw300AUModal';
    m.className='tw-au-modal hidden';
    m.innerHTML='<div class="tw-au-panel"><div class="tw-au-head"><h2>Boekhouding</h2><button id="twAuClose" type="button">Terug</button></div><div class="tw-au-tabs"><button data-tab="facturen" class="active">Facturen</button><button data-tab="klanten">Klanten</button><button data-tab="betalingen">Betalingen</button></div><div class="tw-au-years" id="twAuYears"></div><div class="tw-au-tools"><input id="twAuSearch" placeholder="Zoek factuur, klant, opdracht, titel"><select id="twAuStatus"><option value="all">Alles</option><option value="open">Openstaand</option><option value="paid">Betaald</option></select></div><div id="twAuList"></div></div>';
    document.body.appendChild(m);
