    A('#bnsV56Actions button,#bnsV58OrderActions button,#bnsV57OrderActions button,.bns-v333-order-bottom button').forEach(function(b){
      if(b.dataset.bnsV335Feedback==='1') return;
      b.dataset.bnsV335Feedback='1';
      b.addEventListener('click',function(){
        b.style.filter='brightness(.82)';
        setTimeout(function(){
          b.style.filter='';
        },160);
      },true);
    });
