  if(window.__BNS_V356_ORDERS_TABS_CLEAN__) return;
  window.__BNS_V356_ORDERS_TABS_CLEAN__=true;
  var MODE='running';
  var RENDERING=false; window.BNS_V356_RENDERING=RENDERING;

  function E(id){return document.getElementById(id);} 
