// =============================================================================
(function BNS_V357_ACTIVE_ARCHIEF_CLEANUP(){
  'use strict';
  if(window.__BNS_V357_ACTIVE_ARCHIEF_CLEANUP__) return;
  window.__BNS_V357_ACTIVE_ARCHIEF_CLEANUP__ = true;

  function E(id){ return document.getElementById(id); }
  function A(sel, root){ return Array.prototype.slice.call((root||document).querySelectorAll(sel)); }
  function txt(el){ return String(el && el.textContent || '').replace(/\s+/g,' ').trim(); }
  function low(el){ return txt(el).toLowerCase(); }

  function style(){
    if(E('bns357Style')) return;
    var s=document.createElement('style');
    s.id='bns357Style';
    s.textContent='\
      #orders button.bns-v340-folder, #orders .bns-v340-folderwrap, #orders .bns-v340-title, #orders .bns-v340-toolbar, #orders .bns-v340-folders{display:none!important}\
      #orders button[data-bns-v340-year], #orders button[data-bns-v340-emptyyear]{display:none!important}\
      #orders button.bns350-tab[data-t="active"], #orders button.bns350-tab[data-t="all"], #orders button.bns350-tab[data-t="conf"]{display:none!important}\
    ';
    document.head.appendChild(s);
  }

  function ensureArchiefButton(){
    var b=E('bns350ABtn') || E('bns352ArchiveBtn');
    if(b){
      b.textContent='Archief';
      b.style.display='';
      return;
    }
    var side=document.querySelector('.side')||document.querySelector('.sidebar')||document.querySelector('nav');
    if(!side) return;
    var ref=null;
    A('button,a', side).forEach(function(el){ if(!ref && /^opdrachten$/i.test(txt(el))) ref=el; });
    if(!ref) return;
    b=document.createElement('button');
    b.id='bns350ABtn';
    b.type='button';
    b.textContent='Archief';
    b.className=ref.className || 'nav';
    b.onclick=function(ev){
      if(ev){ev.preventDefault();ev.stopPropagation();}
      try{ if(typeof buildArchPage==='function') buildArchPage(); }catch(e){}
      try{ if(typeof goPage==='function' && typeof renderArch==='function'){ goPage('bns350ArchPage', renderArch, 'bns350ABtn'); return false; } }catch(e){}
      var pg=E('bns350ArchPage')||E('bns352Archive');
      if(pg){ A('.page').forEach(function(p){p.classList.remove('active');}); pg.classList.add('active'); }
      return false;
    };
    ref.parentNode.insertBefore(b, ref.nextSibling);
  }

  function hideActiveButtons(){
    A('#orders button, #orders a').forEach(function(b){
      var t=low(b);
      if(t==='actieve opdrachten' || t==='actief'){
        // Niet de gewenste nieuwe tabs raken: Lopende opdrachten / 14 dagen / Offertes blijven zichtbaar.
        if(!b.classList.contains('bns356-tab')) b.style.display='none';
      }
    });
    // Als oude renderer toch een mappenview heeft geplaatst, verwijder alleen die oude mappenkop/knoppen.
    A('#orders .bns-v340-title,#orders .bns-v340-toolbar,#orders .bns-v340-folders,#orders .bns-v340-folderwrap').forEach(function(x){x.remove();});
  }

  function cleanupCards(){
    var roots=A('#orders .order-card,#orders .bns-v126-order-card,#orders [data-bns-order-id]');
    roots.forEach(function(card){
      // Overzicht bestelling: houd alleen de rechter/laatste knop over.
      var over=A('button,a', card).filter(function(b){return /overzicht\s*bestelling/i.test(txt(b));});
      if(over.length>1){
        over.slice(0, over.length-1).forEach(function(b){b.remove();});
      }
      // Routenet: verwijder brede/dubbele knoppen. Houd alleen bns356-route of bns-routenet-btn naast Waze over.
      var routes=A('button,a', card).filter(function(b){return /^routenet$/i.test(txt(b));});
      if(routes.length>1){
        var keep=routes.find(function(b){return b.classList.contains('bns356-route') || b.classList.contains('bns-routenet-btn');}) || routes[routes.length-1];
        routes.forEach(function(b){ if(b!==keep) b.remove(); });
      }
      routes=A('button,a', card).filter(function(b){return /^routenet$/i.test(txt(b));});
      routes.forEach(function(b){
        var r=b.getBoundingClientRect ? b.getBoundingClientRect() : {width:0,height:0};
        if(r.width>180 || r.height>32){ b.remove(); }
      });
    });
  }

  function clean(){
    style();
    ensureArchiefButton();
    hideActiveButtons();
    cleanupCards();
  }

  // Capture-click: oude Active knop mag nooit de oude mappenrenderer starten.
  document.addEventListener('click', function(ev){
    var b=ev.target && ev.target.closest ? ev.target.closest('button,a') : null;
    if(!b) return;
    var t=low(b);
    if((t==='actieve opdrachten' || t==='actief') && !b.classList.contains('bns356-tab')){
      ev.preventDefault();
      ev.stopPropagation();
      if(ev.stopImmediatePropagation) ev.stopImmediatePropagation();
      hideActiveButtons();
      try{ if(window.BNS_V356_RENDER_ORDERS) window.BNS_V356_RENDER_ORDERS(); }
      catch(e){}
      return false;
    }
  }, true);

  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', function(){setTimeout(clean,100);setTimeout(clean,700);});
  else { setTimeout(clean,50); setTimeout(clean,700); }
  var n=0;
  var tm=setInterval(function(){ clean(); if(++n>30) clearInterval(tm); }, 400);
  try{
    var mo=new MutationObserver(function(){ setTimeout(clean,30); });
    mo.observe(document.documentElement,{childList:true,subtree:true});
  }catch(e){}
  console.info('[BNS v357] Active weg, Archief terug, dubbele overzichtknop schoon.');
})();

// BNS PATCH v358 - Admin Opruimen duidelijker/leesbaar
// Datum: 2026-05-25
// Doel: alleen Admin > Opruimen visueel verbeteren: duidelijke rubrieken en goed zichtbare jaarknoppen.
(function BNS_V358_ADMIN_OPRUIMEN_STIJL(){
  'use strict';
  if(window.__BNS_V358_ADMIN_OPRUIMEN_STIJL__) return;
  window.__BNS_V358_ADMIN_OPRUIMEN_STIJL__ = true;

  function E(id){ return document.getElementById(id); }
  function A(sel, root){ return Array.prototype.slice.call((root||document).querySelectorAll(sel)); }
  function css(){
    if(E('bns358OpruimStyle')) return;
    var s=document.createElement('style');
    s.id='bns358OpruimStyle';
    s.textContent = ''+
      '#bns350AdminPane{background:#f8fafc!important;border:1px solid #dbe3ef!important;border-radius:18px!important;padding:18px!important;color:#111827!important;}'+
      '#bns350AdminPane h3{font-size:22px!important;font-weight:900!important;color:#0f172a!important;margin:0 0 6px!important;}'+
      '#bns350AdminPane p{color:#334155!important;font-size:14px!important;font-weight:700!important;margin:0 0 18px!important;}'+
      '#bns350OpBox{display:grid!important;gap:14px!important;margin-top:10px!important;}'+
      '#bns350OpBox>div{background:#ffffff!important;border:1px solid #cbd5e1!important;border-radius:16px!important;padding:14px 16px!important;margin:0!important;box-shadow:0 4px 14px rgba(15,23,42,.08)!important;}'+
      '#bns350OpBox>div>b{display:block!important;font-size:17px!important;font-weight:900!important;color:#0f172a!important;margin:0 0 10px!important;}'+
      '#bns350OpBox span{color:#475569!important;font-weight:800!important;}'+
      '#bns350OpBox .bns350-delyear{display:inline-flex!important;align-items:center!important;gap:7px!important;border:0!important;border-radius:12px!important;padding:10px 14px!important;margin:4px 6px 4px 0!important;background:#dc2626!important;color:#ffffff!important;font-size:14px!important;font-weight:900!important;cursor:pointer!important;opacity:1!important;filter:none!important;box-shadow:0 3px 10px rgba(220,38,38,.25)!important;}'+
      '#bns350OpBox .bns350-delyear:hover{background:#b91c1c!important;transform:translateY(-1px)!important;}'+
      '#bns350OpBox .bns350-delyear:active{background:#7f1d1d!important;transform:translateY(0)!important;}'+
      '#bns350OpBox .bns358-catnote{display:block!important;color:#475569!important;font-size:13px!important;font-weight:800!important;margin:-4px 0 10px!important;}'+
      '#bns350OpBox .bns358-count{display:inline-flex!important;align-items:center!important;border-radius:999px!important;background:#e0f2fe!important;color:#075985!important;padding:4px 9px!important;font-size:12px!important;font-weight:900!important;margin-left:8px!important;}';
    document.head.appendChild(s);
  }

  function enhance(){
    css();
    var box=E('bns350OpBox');
    if(!box) return;
    A(':scope > div', box).forEach(function(group){
      var title=group.querySelector('b');
      if(!title) return;
      var txt=(title.textContent||'').trim();
      if(group.querySelector('.bns358-catnote')) return;
      var note=document.createElement('span');
      note.className='bns358-catnote';
      if(/Uitgevoerde/i.test(txt)) note.textContent='Opdrachten waarvan de einddatum voorbij is of die uitgevoerd/afgerond zijn.';
      else if(/Geannuleerde/i.test(txt)) note.textContent='Alle opdrachten die geannuleerd zijn. Materiaal is vrij.';
      else if(/Verwijderde/i.test(txt)) note.textContent='Alles wat naar verwijderd is gezet. Wissen is definitief.';
      else if(/Schade/i.test(txt)) note.textContent='Schademeldingen per jaar. Wissen verwijdert ook uit Firebase.';
      else note.textContent='Oude gegevens per jaar opruimen.';
      title.insertAdjacentElement('afterend', note);
      var btns=A('.bns350-delyear', group);
      if(btns.length && !title.querySelector('.bns358-count')){
        var c=document.createElement('span');
        c.className='bns358-count';
        c.textContent=btns.length+' jaarmappen';
        title.appendChild(c);
      }
    });
  }

  function start(){
    css();
    enhance();
    document.addEventListener('click', function(){ setTimeout(enhance,80); }, true);
    var n=0;
    var timer=setInterval(function(){ enhance(); if(++n>12) clearInterval(timer); }, 500);
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', start);
  else start();
  console.info('[BNS v358] Admin Opruimen duidelijker actief.');
})();

// =============================================================================
// BNS PATCH v359 — Stabilisatie: onrust stoppen, mappen uit Opdrachten houden
// Datum: 2026-05-25
//
// Drie gerichte fixes:
//
//  1. MUTATIONOBSERVER-LOOP STOPPEN
//     v356 en v357 hebben elk een MutationObserver op document.documentElement
//     met subtree:true. Die vuren bij elke DOM-wijziging → roepen clean() /
//     hideArchiveBad() aan → wijzigen de DOM → triggeren zichzelf opnieuw.
//     Fix: we overschrijven de globale MutationObserver constructor tijdelijk
//     zodat nieuwe subtree-observers op documentElement worden geblokkeerd
//     zodra v356/v357 al actief zijn. Bestaande observers worden gedisconnect.
//
//  2. RENDERYEARS / RENDERDONEFOLDERS WRAPPEN
//     renderYears() en renderDoneFolders() mogen nooit worden aangeroepen
//     terwijl de #orders pagina actief is. Alleen op Archief-pagina's is
//     een mappenweergave toegestaan.
//
//  3. BINDVIEWS NEUTRALISEREN VOOR ORDERS-PAGINA
//     bindViews() hangt listeners aan knoppen voor cancelled/done/deleted.
//     Die knoppen bestaan niet meer in de orders-pagina (v357 verbergt ze),
//     maar als ze toch zichtbaar zijn onderschept deze patch de klik en
//     stuurt door naar de archief-pagina.
// =============================================================================

(function BNS_V359_STABILISATIE() {
  'use strict';
  if (window.__BNS_V359__) return;
  window.__BNS_V359__ = true;

  // ─── Helpers ────────────────────────────────────────────────────────────────

  function isOrdersActive() {
    var p = document.getElementById('orders');
    return p && p.classList.contains('active');
  }

  function isArchivePage() {
    var p = document.getElementById('bns350ArchPage') ||
            document.getElementById('bns352Archive');
    return p && p.classList.contains('active');
  }

  // ─── 1. MutationObserver-loop stoppen ───────────────────────────────────────
  // Strategie: bewaar lijst van alle observers die op documentElement/body
  // met subtree:true observeren. Na installatie van v356/v357 (500ms)
  // disconnecten we alle observers waarvan we weten dat ze de loop veroorzaken.

  var _blocked = [];

  function neutraliseBadObservers() {
    // We kunnen bestaande observers niet direct stoppen zonder referentie.
    // Maar v356 en v357 slaan hun observers niet op - we moeten de
    // MutationObserver constructor patchen om toekomstige te blokkeren
    // en de DOM-mutaties die de loop veroorzaken te debounce-n.

    if (window.__BNS_V359_MO_PATCHED__) return;
    window.__BNS_V359_MO_PATCHED__ = true;

    var OrigMO = window.MutationObserver;
    if (!OrigMO) return;

    function PatchedMO(cb) {
      var _cb = cb;
      var _debounceTimer = null;
      var _this = new OrigMO(function(mutations) {
        // Als de callback clean()/hideArchiveBad() aanroept terwijl orders actief is:
        // debounce sterk zodat de loop wordt gebroken
        if (_debounceTimer) return; // skip als er al een timer loopt
        _debounceTimer = setTimeout(function() {
          _debounceTimer = null;
          try { _cb(mutations); } catch(e) {}
        }, 800); // 800ms debounce - breekt de loop maar houdt functionaliteit
      });
      _blocked.push(_this);
      return _this;
    }
    PatchedMO.prototype = OrigMO.prototype;

    // Patch alleen NIEUWE observers - bestaande (v356/v357) laten we met rust
    // maar we voegen een globale debounce toe via het DOM zelf
    try {
      window.MutationObserver = PatchedMO;
    } catch(e) {}
  }

  // ─── 2. renderYears en renderDoneFolders wrappen ─────────────────────────────

  function wrapFolderRenderers() {
    // renderYears
    var origRY = window.renderYears;
    if (origRY && !origRY.__bns359) {
      window.renderYears = function(v, title) {
        // Alleen toestaan als we NIET op de orders-pagina staan
        if (isOrdersActive()) {
          console.log('[BNS v359] renderYears("'+v+'") geblokkeerd op orders-pagina');
          // Roep in plaats daarvan de v356 renderer aan
          try {
            if (typeof window.BNS_V356_RENDER_ORDERS === 'function') {
              window.BNS_V356_RENDER_ORDERS();
            }
          } catch(e) {}
          return false;
        }
        return origRY.apply(this, arguments);
      };
      window.renderYears.__bns359 = true;
      try { renderYears = window.renderYears; } catch(e) {}
    }

    // renderDoneFolders
    var origRDF = window.renderDoneFolders;
    if (origRDF && !origRDF.__bns359) {
      window.renderDoneFolders = function() {
        if (isOrdersActive()) {
          console.log('[BNS v359] renderDoneFolders() geblokkeerd op orders-pagina');
          try {
            if (typeof window.BNS_V356_RENDER_ORDERS === 'function') {
              window.BNS_V356_RENDER_ORDERS();
            }
          } catch(e) {}
          return false;
        }
        return origRDF.apply(this, arguments);
      };
      window.renderDoneFolders.__bns359 = true;
      try { renderDoneFolders = window.renderDoneFolders; } catch(e) {}
    }
  }

  // ─── 3. Klikken op archief-knoppen in orders-pagina onderscheppen ────────────

  var ARCH_WORDS = ['geannuleerde opdrachten', 'uitgevoerde opdrachten',
                    'verwijderde opdrachten', 'toekomstige opdrachten',
                    'actieve opdrachten per jaar'];

  function goToArchief() {
    // Navigeer naar archief-pagina als die bestaat
    var archPage = document.getElementById('bns350ArchPage') ||
                   document.getElementById('bns352Archive');
    if (!archPage) return;
    document.querySelectorAll('.page').forEach(function(p) {
      p.classList.remove('active');
    });
    archPage.classList.add('active');
    // Trigger render
    try {
      if (typeof window.renderArch === 'function') window.renderArch();
    } catch(e) {}
  }

  document.addEventListener('click', function(ev) {
    if (!isOrdersActive()) return;
    var btn = ev.target && ev.target.closest ? ev.target.closest('button, a') : null;
    if (!btn) return;
    var t = (btn.textContent || '').toLowerCase().replace(/\s+/g,' ').trim();
    if (ARCH_WORDS.some(function(w) { return t.indexOf(w) >= 0; })) {
      // Is het een bns356-tab? Dan niet blokkeren
      if (btn.classList && btn.classList.contains('bns356-tab')) return;
      ev.preventDefault();
      ev.stopImmediatePropagation();
      goToArchief();
      return false;
    }
  }, true);

  // ─── 4. Dashboard onrust: applyOrderChipColors debounce ─────────────────────
  // applyOrderChipColors loopt elke 1500ms en doet DOM-wijzigingen op dashboard.
  // We throttlen dit zodat het niet meer dan 1x per 3s vuurt.

  function throttleDashboardUpdates() {
    var orig = window.applyOrderChipColors;
    if (!orig || orig.__bns359t) return;
    var _last = 0;
    var throttled = function() {
      var now = Date.now();
      if (now - _last < 3000) return;
      _last = now;
      return orig.apply(this, arguments);
    };
    throttled.__bns359t = true;
    window.applyOrderChipColors = throttled;
    try { applyOrderChipColors = throttled; } catch(e) {}

    // Zelfde voor cleanPlannerDashboard
    var orig2 = window.cleanPlannerDashboard;
    if (orig2 && !orig2.__bns359t) {
      var _last2 = 0;
      var throttled2 = function() {
        var now = Date.now();
        if (now - _last2 < 3000) return;
        _last2 = now;
        return orig2.apply(this, arguments);
      };
      throttled2.__bns359t = true;
      window.cleanPlannerDashboard = throttled2;
      try { cleanPlannerDashboard = throttled2; } catch(e) {}
    }
  }

  // ─── Installatie ─────────────────────────────────────────────────────────────

  function install() {
    neutraliseBadObservers();
    wrapFolderRenderers();
    throttleDashboardUpdates();
  }

  // Wacht tot v356/v357 geladen zijn (die lopen zelf ook 500ms na DOMContentLoaded)
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function() {
      setTimeout(install, 200);
      setTimeout(install, 1500); // tweede ronde na v356/v357 intervals
    });
  } else {
    setTimeout(install, 200);
    setTimeout(install, 1500);
  }

  // Periodiek wrappen herinstalleren (renderYears kan overschreven worden)
  setInterval(wrapFolderRenderers, 5000);

  console.info('[BNS v359] Stabilisatie actief. MutationObserver debounced. renderYears/renderDoneFolders gepatcht.');
})();

