    var names = uniq([].concat(arr(o.driverNames),arr(o.bezorgerNames),arr(o.assignedDriverNames),arr(o.driverName),arr(o.driver),arr(o.bezorger),arr(o.bezorgerName),arr(o.assignedDriver),arr(o.assignedDriverName)));
