    if(d==='opdracht' || t==='maak opdrachtdocument' || t==='maak opdrachtbevestiging' || t.indexOf('opdrachtbevestiging')>=0 || t.indexOf('overzicht / opdracht')>=0) return 'opdrachtbevestiging';
    return '';
