  function saveNow(){ try{ if(typeof save==='function') save(); }catch(e){} try{ if(typeof saveState==='function') saveState(); }catch(e){} try{ localStorage.setItem('event-planner-pro-amsterdam-verhuur-v1', JSON.stringify(S())); }catch(e){} }
