        if(ev){ ev.preventDefault(); ev.stopPropagation(); if(ev.stopImmediatePropagation) ev.stopImmediatePropagation(); }
        if(area) area.classList.remove('hidden');
        if(input) input.value = '';
        normalizeState();
        saveSilent();
        setTimeout(scrubVisible, 0);
        return false;
